mapper.select:
select rc.id, rc.classroom_code as classroomCode, rc.classroom_name as classroomName, rc.building_id as buildingId, rb.building_code as buildingCode, rb.building_name as buildingName, rc.seat_count as seatCount, rc.room_type as roomType, rc.status, rc.remark from res_classroom rc left join res_building rb on rb.id = rc.building_id and rb.deleted = 0 where rc.deleted = 0
and ( rc.classroom_code like concat('%', #{query.keyword}, '%') or rc.classroom_name like concat('%', #{query.keyword}, '%') or rb.building_code like concat('%', #{query.keyword}, '%') or rb.building_name like concat('%', #{query.keyword}, '%') )
and rb.building_code = #{query.buildingCode}
and rc.status = #{query.status}
order by rc.updated_at desc, rc.id desc
